import{_ as a,o as r,c as e,a5 as o}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"RLC 充放电仿真","description":"","frontmatter":{"title":"RLC 充放电仿真","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/RLCSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/RLCSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/RLCSim.md","filePath":"content/motor/simulations/RLCSim.md","lastUpdated":null}'),i={name:"content/motor/simulations/RLCSim.md"};function n(l,t,s,d,c,h){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="rlc-充放电仿真" tabindex="-1">RLC 充放电仿真 <a class="header-anchor" href="#rlc-充放电仿真" aria-label="Permalink to &quot;RLC 充放电仿真&quot;">​</a></h1><h4 id="rlc-充放电仿真-1" tabindex="-1">RLC 充放电仿真 <a class="header-anchor" href="#rlc-充放电仿真-1" aria-label="Permalink to &quot;RLC 充放电仿真&quot;">​</a></h4><h2 id="📖-教学说明-—-理解-rlc-电路响应" tabindex="-1">📖 教学说明 — 理解 RLC 电路响应 <a class="header-anchor" href="#📖-教学说明-—-理解-rlc-电路响应" aria-label="Permalink to &quot;📖 教学说明 — 理解 RLC 电路响应&quot;">​</a></h2><h5 id="电路原理" tabindex="-1">电路原理 <a class="header-anchor" href="#电路原理" aria-label="Permalink to &quot;电路原理&quot;">​</a></h5><p>本仿真模拟 <strong>串联 RLC 电路</strong>在阶跃电压输入下的电容电压响应 Vc(t)。</p><p><strong>阻尼比计算公式</strong>：<code>ζ = (R/2) · √(C/L)</code></p><ul><li><p><strong>增大 R</strong> → ζ 增大 → 阻尼增强 → 振荡衰减更快</p></li><li><p><strong>增大 L</strong> → ζ 减小 → 阻尼减弱 → 更容易振荡</p></li><li><p><strong>增大 C</strong> → ζ 增大、ωn 减小 → 响应变慢</p></li></ul><h5 id="三种阻尼状态对比" tabindex="-1">三种阻尼状态对比 <a class="header-anchor" href="#三种阻尼状态对比" aria-label="Permalink to &quot;三种阻尼状态对比&quot;">​</a></h5><table tabindex="0"><thead><tr><th>状态</th><th>条件</th><th>波形特征</th><th>稳态建立</th></tr></thead><tbody><tr><td>过阻尼</td><td>ζ &gt; 1</td><td>单调上升，无振荡</td><td>最慢</td></tr><tr><td>临界阻尼</td><td>ζ = 1</td><td>单调上升，无振荡</td><td>最快（无超调）</td></tr><tr><td>欠阻尼</td><td>ζ</td><td></td><td></td></tr></tbody></table><h5 id="电机控制中的应用" tabindex="-1">电机控制中的应用 <a class="header-anchor" href="#电机控制中的应用" aria-label="Permalink to &quot;电机控制中的应用&quot;">​</a></h5><ul><li><p><strong>Buck 变换器 LC 输出滤波</strong>：设计时需保证 ζ 足够大（通常 ≥ 0.5），避免输出电压振荡。过小的输出电容或过大的滤波电感会导致 ζ 过小。</p></li><li><p><strong>EMI 滤波</strong>：输入端的 LC 滤波器在特定频率可能谐振，需加阻尼电阻或 RC 吸收网络。</p></li><li><p><strong>LLC 谐振变换器</strong>：利用 LC 谐振实现 ZVS（零电压开关），工作在欠阻尼区（Q 值由负载决定）。</p></li><li><p><strong>电流采样滤波</strong>：电机相电流采样后的 RC 低通滤波，截止频率 fc = 1/(2πRC)，需远高于电流环带宽。</p></li></ul>',11)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
